module slam_system(  
    input clk,  
    input reset,  
    input trigger,  
    output reg [1:0] state  
);  

    parameter IDLE = 2'b00,  
              MAPPING = 2'b01,  
              LOCALIZING = 2'b10;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset)  
            state <= IDLE;  
        else if (trigger) begin  
            case (state)  
                IDLE: state <= MAPPING;  
                MAPPING: state <= LOCALIZING;  
                LOCALIZING: state <= IDLE;  
                default: state <= IDLE;  
            endcase  
        end  
    end  
endmodule
